mapper.select:
sp.deposit_product_id AS depositProductId, sp.kor_co_nm AS korCoNm, sp.fin_prdt_cd AS finPrdtCd, sp.fin_prdt_nm AS finPrdtNm, sp.max_limit AS maxLimit, sp.spcl_cnd AS benefit, CASE WHEN uf.favorite_id IS NOT NULL THEN TRUE ELSE FALSE END AS isStarred, COALESCE(lc.like_count, 0) AS likeCount,
CASE WHEN EXISTS ( SELECT 1 FROM user_likes ul WHERE ul.deposit_product_id = sp.deposit_product_id AND ul.user_id = #{userId} ) THEN TRUE ELSE FALSE END AS isLiked,
FALSE AS isLiked,
FROM deposit_product sp
/* 즐겨찾기 */ LEFT JOIN user_favorites uf ON uf.deposit_product_id = sp.deposit_product_id
AND uf.user_id = #{userId}
AND 1 = 0
/* 좋아요 개수 집계 (예금만) */ LEFT JOIN ( SELECT deposit_product_id, COUNT(DISTINCT user_id) AS like_count FROM user_likes WHERE deposit_product_id IS NOT NULL GROUP BY deposit_product_id ) lc ON lc.deposit_product_id = sp.deposit_product_id
WHERE 1 = 1
AND sp.kor_co_nm LIKE CONCAT('%', #{korCoNm}, '%')
AND CAST(REPLACE(sp.max_limit, ',', '') AS UNSIGNED) <= #{maxLimit}
